#!/usr/bin/env node
//
// verify-plugin-pack.mjs — assert the publishable tarball actually contains the
// compiled Expo config plugin that app.plugin.js require()s.
//
// Background (issue #64): plugin/build/ is gitignored and regenerated by
// prepack, then shipped via the package.json `files` allowlist. A bare
// "plugin/build" entry is honored by `npm pack` but DROPPED by `yarn pack`
// (Yarn 4 does not recurse nested bare-dir entries), so v0.4.0 — packed with
// Yarn — shipped app.plugin.js without its plugin/build/ directory, crashing
// every Expo consumer at config-resolution time. The fix is the recursive glob
// "plugin/build/**".
//
// The Jest test (__tests__/expo-plugin-packaging.test.ts) is a fast, static
// regression check on the `files` config. THIS script is the heavier,
// authoritative gate: it drives the real packers and inspects what they would
// ship. Run it before publishing — `yarn verify:pack`. It is wired into the
// library's `prepublishOnly` so `npm publish` fails closed; run it manually
// first if you publish via `yarn npm publish` (Yarn does not run
// prepublishOnly).
//
// Each packer runs its own prepack (nitrogen + bob + tsc), so this takes a
// minute or two — it is a publish-time gate, deliberately not part of the unit
// test suite.

import { spawnSync } from 'node:child_process';
import { dirname, join } from 'node:path';
import { fileURLToPath } from 'node:url';

const repoRoot = join(dirname(fileURLToPath(import.meta.url)), '..');
const pkgDir = join(repoRoot, 'packages', 'react-native-video-pipeline');

// Paths that MUST appear in the packed tarball, relative to the package root.
const REQUIRED = ['app.plugin.js', 'plugin/build/index.js'];

function run(cmd, args) {
  // Both packers print the file manifest, but on different streams — npm to
  // stderr ("npm notice …"), yarn to stdout ("➤ YN0000: …"). Capture and merge
  // both so the scan is stream-agnostic. spawnSync (unlike execFileSync, which
  // only returns stdout) hands back stderr on success too.
  const res = spawnSync(cmd, args, {
    cwd: pkgDir,
    encoding: 'utf8',
    stdio: ['ignore', 'pipe', 'pipe'],
  });
  return {
    output: `${res.stdout ?? ''}\n${res.stderr ?? ''}`,
    status: res.status,
    error: res.error,
  };
}

function check(label, { output, status, error }) {
  // A packer that errored out (or exited nonzero) may still have printed a
  // partial manifest before dying — never trust the text in that case.
  if (error) {
    console.error(`✗ ${label}: packer failed to run — ${error.message}`);
    return false;
  }
  if (status !== 0) {
    console.error(`✗ ${label}: packer exited ${status} (no tarball produced)`);
    return false;
  }
  const missing = REQUIRED.filter((p) => !output.includes(p));
  if (missing.length > 0) {
    console.error(`✗ ${label}: tarball is MISSING ${missing.join(', ')}`);
    return false;
  }
  console.error(`✓ ${label}: ships ${REQUIRED.join(', ')}`);
  return true;
}

console.error('Verifying the Expo config plugin is packed (issue #64)…\n');

// Yarn is the load-bearing case: it is the packer that dropped the directory in
// v0.4.0, so its result gates the script.
const yarnOk = check('yarn pack ', run('yarn', ['pack', '--dry-run']));
// npm parity check — it always shipped the plugin, so this is a canary that the
// fix did not regress the other packer.
const npmOk = check('npm pack  ', run('npm', ['pack', '--dry-run']));

if (!yarnOk || !npmOk) {
  console.error(
    '\nThe publishable tarball would omit the Expo config plugin. ' +
      'Check the `files` allowlist in packages/react-native-video-pipeline/' +
      'package.json (the plugin/build entry must be the recursive glob ' +
      '"plugin/build/**"). See issue #64.',
  );
  process.exit(1);
}

console.error('\nAll packers ship the compiled Expo config plugin.');
